import json; import pandas as pd; import re; pkg_file = '/tmp/tmpbpuw6w7j.json'; pkg_version_file = '/tmp/tmpe4z5e_x0.json'; proj_info_file = '/tmp/tmpv3z_1v8v.json'; print('Reading data files...'); packages = json.load(open(pkg_file)); pkgversions = json.load(open(pkg_version_file)); projinfo = json.load(open(proj_info_file)); print(f'Loaded {len(packages)} packages, {len(pkgversions)} package versions, {len(projinfo)} project infos'); df_packages = pd.DataFrame(packages); df_pkgversions = pd.DataFrame(pkgversions); df_projinfo = pd.DataFrame(projinfo); mit_packages = []; 
for idx, pkg in df_packages.iterrows():
    if pkg['System'] != 'NPM': continue
    try:
        licenses = json.loads(pkg['Licenses'])
        version_info = json.loads(pkg['VersionInfo'].replace('\n', '').strip())
        if 'MIT' in licenses and version_info.get('IsRelease', False) == True:
            mit_packages.append(pkg.to_dict())
    except: continue

print('MIT release packages:', len(mit_packages))
if len(mit_packages) == 0:
    result = {'error': 'No MIT-licensed release packages found'}
else:
    df_mit = pd.DataFrame(mit_packages)
    df_merged = pd.merge(df_mit, df_pkgversions, on=['System', 'Name', 'Version'], how='inner')
    print('After merge:', len(df_merged))
    df_projinfo['ForkCount'] = df_projinfo['Project_Information'].apply(lambda x: int(re.search(r'(\d+)\s+forks?', str(x), re.I).group(1)) if re.search(r'(\d+)\s+forks?', str(x), re.I) else 0)
    projects = {}
    for _, row in df_merged.iterrows():
        proj = row['ProjectName']
        if pd.isna(proj): continue
        matches = df_projinfo[df_projinfo['Project_Information'].str.contains(proj, na=False)]
        if len(matches) > 0:
            forks = matches.iloc[0]['ForkCount']
            if forks > 0: projects[proj] = max(projects.get(proj, 0), forks)
    top5 = sorted(projects.items(), key=lambda x: x[1], reverse=True)[:5]
    result = {'top_5': top5, 'total_mit': len(mit_packages), 'total_merged': len(df_merged), 'projects_found': len(projects)}
print('__RESULT__:')
print(json.dumps(result))

