def check_mit(lic): return 'MIT' in json.loads(lic)
def check_release(ver): return json.loads(ver.replace('\n', '').strip()).get('IsRelease', False) == True
df_filtered = df_pkg[df_pkg['Licenses'].apply(check_mit) & df_pkg['VersionInfo'].apply(check_release)]; 
# Merge with versions to get project names
df_merged = pd.merge(df_filtered, df_ver[['System','Name','Version','ProjectName']], on=['System','Name','Version'], how='inner'); 
# Extract forks from project info
df_proj['Forks'] = df_proj['Project_Information'].apply(lambda x: int(re.search(r'(\d+)\s+forks', str(x), re.I).group(1)) if re.search(r'(\d+)\s+forks', str(x), re.I) else 0); 
# Map project names to fork counts
proj_forks = {}; 
for _, row in df_merged.iterrows():
    if pd.isna(row['ProjectName']): continue
    proj_name = row['ProjectName']; 
    matches = df_proj[df_proj['Project_Information'].str.contains(proj_name, na=False, regex=False)]
    if len(matches) > 0: proj_forks[proj_name] = matches.iloc[0]['Forks']
# Get top 5 by forks
top5 = sorted([(k, v) for k, v in proj_forks.items() if v > 0], key=lambda x: x[1], reverse=True)[:5]; 
result = {'top_5': top5, 'total_packages': len(df_merged), 'projects_with_forks': len([f for f in proj_forks.values() if f > 0])}; print('__RESULT__:'); print(json.dumps(result))

