import json, pandas as pd, re

pkg_data = json.load(open('/tmp/tmphj3z6y8y.json'))
ver_data = json.load(open('/tmp/tmpt2c8m5k6.json'))
proj_data = locals()['var_functions.query_db:6']

# Convert to DataFrames
df_pkg = pd.DataFrame(pkg_data)
df_ver = pd.DataFrame(ver_data)
df_proj = pd.DataFrame(proj_data)

# Filter for MIT license and release status
mit_packages = []
for _, p in df_pkg.iterrows():
    try:
        if 'MIT' in json.loads(p['Licenses']):
            ver_info = json.loads(p['VersionInfo'].replace('\n', '').strip())
            if ver_info.get('IsRelease', False) == True:
                mit_packages.append({
                    'System': p['System'],
                    'Name': p['Name'],
                    'Version': p['Version']
                })
    except:
        continue

# Create version lookup
ver_lookup = {}
for _, v in df_ver.iterrows():
    ver_lookup[(v['System'], v['Name'], v['Version'])] = v['ProjectName']

# Extract fork counts from project info
proj_forks = {}
for _, proj in df_proj.iterrows():
    info = proj['Project_Information']
    if isinstance(info, str):
        match = re.search(r'(\d+)\s+forks', info, re.I)
        if match:
            proj_forks[info] = int(match.group(1))

# Map packages to projects
project_fork_counts = {}
for pkg in mit_packages:
    key = (pkg['System'], pkg['Name'], pkg['Version'])
    proj_name = ver_lookup.get(key)
    if proj_name and proj_name not in project_fork_counts:
        for proj_info, forks in proj_forks.items():
            if proj_name in proj_info:
                project_fork_counts[proj_name] = forks
                break

# Get top 5
top5 = sorted(project_fork_counts.items(), key=lambda x: x[1], reverse=True)[:5]

result = {
    'top_5': top5,
    'total_packages': len(mit_packages),
    'projects_mapped': len(project_fork_counts)
}

print('__RESULT__:')
print(json.dumps(result))

