proj_data = locals()['var_functions.query_db:6']

with open(pkg_path, 'r') as f:
    packages = json.load(f)
with open(ver_path, 'r') as f:
    versions = json.load(f)
projects = proj_data

mit_packages = []
for p in packages:
    if 'MIT' in p.get('Licenses', ''):
        try:
            ver_info = json.loads(p['VersionInfo'].replace('\n', '').strip())
            if ver_info.get('IsRelease'):
                mit_packages.append(p)
        except:
            continue

ver_map = {}
for v in versions:
    key = (v['System'], v['Name'], v['Version'])
    ver_map[key] = v['ProjectName']

project_forks = {}
for proj in projects:
    info = proj['Project_Information']
    match = re.search(r'(\d+)\s+forks', str(info), re.I)
    if match:
        project_forks[info] = int(match.group(1))

matched_projects = {}
for pkg in mit_packages:
    key = (pkg['System'], pkg['Name'], pkg['Version'])
    proj = ver_map.get(key)
    if proj and proj not in matched_projects:
        for info, forks in project_forks.items():
            if proj in info:
                matched_projects[proj] = forks
                break

top5 = sorted(matched_projects.items(), key=lambda x: x[1], reverse=True)[:5]

